@Service
public class MfaService {
    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;

    public MfaService(UserRepository userRepository, BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    public String generateBackupCode() {
        StringBuilder code = new StringBuilder();
        Random random = new Random();
        for (int i = 0; i < 16; i++) {
            code.append(random.nextInt(10));
        }
        return code.toString();
    }

    public List<String> generateBackupCodes(int count) {
        List<String> codes = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            codes.add(generateBackupCode());
        }
        return codes;
    }

    public User enableMfa(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new RuntimeException("User not found"));

        if (user.isMfaEnabled()) {
            throw new RuntimeException("MFA already enabled");
        }

        List<String> codes = generateBackupCodes(10);
        List<BackupCode> backupCodes = new ArrayList<>();

        for (String code : codes) {
            BackupCode backupCode = new BackupCode(user, code);
            backupCodes.add(backupCode);
        }

        user.setMfaEnabled(true);
        user.setBackupCodes(backupCodes);
        return userRepository.save(user);
    }

    public boolean validateBackupCode(String code) {
        Optional<BackupCode> backupCodeOptional = backupCodeRepository.findByCodeAndUsedFalse(code);
        if (backupCodeOptional.isPresent()) {
            BackupCode backupCode = backupCodeOptional.get();
            backupCode.setUsed(true);
            backupCodeRepository.save(backupCode);
            return true;
        }
        return false;
    }
}

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    private final MfaService mfaService;

    public MfaController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/enable")
    public ResponseEntity<?> enableMfa(@RequestParam String username) {
        try {
            User user = mfaService.enableMfa(username);
            List<String> backupCodes = user.getBackupCodes().stream()
                    .map(BackupCode::getCode)
                    .collect(ArrayList::new, ArrayList::add, ArrayList::addAll);
            return ResponseEntity.ok().body(backupCodes);
        } catch (Exception e) {
            return ResponseEntity.badRequest().body(e.getMessage());
        }
    }

    @PostMapping("/authenticate")
    public ResponseEntity<?> authenticateWithBackupCode(@RequestParam String code) {
        boolean isValid = mfaService.validateBackupCode(code);
        if (isValid) {
            return ResponseEntity.ok().body("Authentication successful");
        } else {
            return ResponseEntity.status(401).body("Invalid backup code");
        }
    }
}

@Configuration
@EnableWebSecurity
public class SecurityConfig {
    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http.csrf().disable()
            .authorizeHttpRequests(authz -> authz
                .requestMatchers("/api/mfa/enable", "/api/mfa/authenticate").authenticated()
                .anyRequest().permitAll()
            )
            .httpBasic().and()
            .sessionManagement().sessionCreationPolicy(SessionCreationPolicy.STATELESS);
        return http.build();
    }
}